mapper.select:
SELECT h.id, h.house_code, h.unit_id, u.unit_name, bd.id AS building_id, bd.building_name, c.id AS community_id, c.community_name, h.floor, h.building_area, h.usable_area, h.house_status, h.house_type, h.remark, h.create_time, h.update_time FROM bs_house h LEFT JOIN bs_unit u ON h.unit_id = u.id LEFT JOIN bs_building bd ON u.building_id = bd.id LEFT JOIN bs_community c ON bd.community_id = c.id WHERE h.del_flag = 0
AND h.house_code LIKE CONCAT('%', #{query.houseCode}, '%')
AND h.unit_id = #{query.unitId}
AND bd.id = #{query.buildingId}
AND c.id = #{query.communityId}
AND h.floor = #{query.floor}
AND h.house_status = #{query.houseStatus}
AND h.house_type = #{query.houseType}
ORDER BY h.create_time DESC
